#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame


   vec2 zoom = 2;//-vRadius*((q3+q4)%5);
   vec2 c;
    c = vec2(1+q8,1+q7)+0.9;
//c=vec2(0.7,0.6);
   vec2 z = (vUv-0.5)*zoom;
   float zp = 0.3+(abs(q3-q4+(q1-q2)*2)%9+5)*0.08;

   vec2 uv2;
for (int i = 0; i < 3; i++)
{
  z = cpow(z,zp)%c;
}

uv2 = z;

uv2 = 0.5 + (1.0 - abs( fract( uv2 * 0.5 ) * 2 - 1.0 )-0.5)*0.99; // Eo.S. mirror code with cutted borders

    float mrad = getRad(uv2);
    float mang = getAng(uv2);


    vec3 fractal = texture( sampler_main, uv2 ).xyz;
    vec3 blured = GetBlur1(uv2);

//float flag = mang*0.3 < mrad-0.7;
ret = fractal*0.5;
ret *= mang*0.3 < mrad-0.7;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv2.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q3         && ret.x<= q24*q1        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q1         && ret.y<= q25*q2        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q2         && ret.z<= q26*q3        )ret.x -= (noise9).z*.5;
ret += (ret==0)*blured*2;

    ret *= 0.9; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 rotate_uv = 0.5-uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2);
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.3, vec2(q11,q12));
vUv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ));
vec2 uvo = vUv;
vUv = (vUv-0.5);
factorA = vUv+ vec2(q1,q2);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv1 = product;
factorA = vUv+ vec2(q3,q4);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv2 = product;
factorA = vUv+ vec2(q5,q6);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv3 = product;
factorA = vUv+ vec2(q7,q8);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv4 = product;
factorA = uv1;
factorB = uv2;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv12 = product;
factorA = uv3;
factorB = uv4;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv34 = product;
factorA = uv12;
factorB = uv34;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
numerator = vec2(1,0);
denominator = product;
fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction*(16);
vUv = mix(0.5 + (uvo-0.5)*(2+(audioLowSmooth-audioHighSmooth)*0.02),vUv+0.5,0.5);

float l = length(vUv-0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5); // Eo.S. mirror code with cutted borders

ret = texture( sampler_fc_main, vUv );
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv12.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q30
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;
ret = mix(1.1-ret,clamp01(texture(sampler_rand00,vUv)-0.1),-ret*1.1+1.5)*clamp01(1-l*l*l*0.001337);

  fragColor = ret;
}
